vector<string> split(const
string& str, const string& delimiter) {
vector<string>
result;
size_t start = 0;
size_t end =
str.find(delimiter);
while (end !=
string::npos) {
result.push_back(str.substr(start, end - start));
start = end + delimiter.length();
end = str.find(delimiter, start);
}
//
添加最后一个部分
result.push_back(str.substr(start));
return result;
}
bool judegeNumber(string& s) {
// 1.
不能为空
if (s.empty()) return
false;
// 2.
判断是否全是数字
for (char c : s) {
if (!isdigit(c)) return false;
}
// 3.
转成整数
int num = stoi(s);
// 4.
判断范围
return num >= 1
&& num <= 9999;
}
